import React, { useState, useEffect } from 'react';
import { ArrowRight, CheckCircle, Users, Gift, Star, Settings, Heart } from 'lucide-react';

// LG 라이프케어 서비스 소개 랜딩페이지 컴포넌트
const LGLifecareServiceSite = () => {
  // 상태 관리: 메뉴, 스크롤, 모바일, 통계 애니메이션
  const [activeTab, setActiveTab] = useState('overview');
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMobile, setIsMobile] = useState(false);
  const [stats, setStats] = useState({ companies: 0, employees: 0, products: 0, brands: 0 });

  // 모바일 화면 감지
  useEffect(() => {
    const checkMobile = () => setIsMobile(window.innerWidth < 768);
    window.addEventListener('resize', checkMobile);
    checkMobile();
    return () => window.removeEventListener('resize', checkMobile);
  }, []);

  // 스크롤 감지
  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 50);
    window.addEventListener('scroll', handleScroll);
    handleScroll();
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // 통계 숫자 애니메이션
  useEffect(() => {
    const interval = setInterval(() => {
      setStats(prev => {
        const newStats = { ...prev };
        if (newStats.companies < 1000) newStats.companies += 10;
        if (newStats.employees < 100) newStats.employees += 1;
        if (newStats.products < 100) newStats.products += 1;
        if (newStats.brands < 10) newStats.brands += 0.1;
        if (newStats.companies >= 1000 && newStats.employees >= 100 && newStats.products >= 100 && newStats.brands >= 10) {
          clearInterval(interval);
        }
        return newStats;
      });
    }, 20);
    return () => clearInterval(interval);
  }, []);

  const toggleMenu = () => setIsMenuOpen(!isMenuOpen);

  return (
    <div className="bg-white min-h-screen">
      {/* 헤더: 서비스명, 네비게이션 */}
      <header className={`fixed w-full z-50 transition-all duration-300 ${isScrolled ? 'bg-white shadow-md py-3' : 'bg-transparent py-5'}`}>
        <div className="container mx-auto px-4">
          <div className="flex justify-between items-center">
            <div className="flex items-center">
              <div className="text-2xl font-bold text-blue-600">LG 라이프케어</div>
            </div>
            {/* 데스크탑 네비게이션 */}
            <nav className="hidden md:flex space-x-8">
              <a href="#overview" onClick={() => setActiveTab('overview')} className={`font-medium ${activeTab === 'overview' ? 'text-blue-600' : 'text-gray-600 hover:text-blue-600'}`}>서비스 개요</a>
              <a href="#benefits" onClick={() => setActiveTab('benefits')} className={`font-medium ${activeTab === 'benefits' ? 'text-blue-600' : 'text-gray-600 hover:text-blue-600'}`}>프리미엄 혜택</a>
              <a href="#platform" onClick={() => setActiveTab('platform')} className={`font-medium ${activeTab === 'platform' ? 'text-blue-600' : 'text-gray-600 hover:text-blue-600'}`}>통합 복지몰</a>
              <a href="#cases" onClick={() => setActiveTab('cases')} className={`font-medium ${activeTab === 'cases' ? 'text-blue-600' : 'text-gray-600 hover:text-blue-600'}`}>고객 사례</a>
              <a href="#contacts" onClick={() => setActiveTab('contacts')} className={`font-medium ${activeTab === 'contacts' ? 'text-blue-600' : 'text-gray-600 hover:text-blue-600'}`}>도입 문의</a>
            </nav>
            {/* 모바일 메뉴 버튼 */}
            <button className="md:hidden" onClick={toggleMenu}>
              <svg className="w-6 h-6 text-gray-700" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
                {isMenuOpen ? (
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path>
                ) : (
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6h16M4 12h16M4 18h16"></path>
                )}
              </svg>
            </button>
            <button className="hidden md:block bg-blue-600 text-white px-6 py-2 rounded-md font-medium hover:bg-blue-700 transition-colors">체험하기</button>
          </div>
          {/* 모바일 네비게이션 */}
          {isMenuOpen && isMobile && (
            <div className="absolute top-16 left-0 right-0 bg-white shadow-md py-4 z-50">
              <div className="flex flex-col space-y-4 px-4">
                <a href="#overview" onClick={() => {setActiveTab('overview'); setIsMenuOpen(false);}} className={`font-medium ${activeTab === 'overview' ? 'text-blue-600' : 'text-gray-600'}`}>서비스 개요</a>
                <a href="#benefits" onClick={() => {setActiveTab('benefits'); setIsMenuOpen(false);}} className={`font-medium ${activeTab === 'benefits' ? 'text-blue-600' : 'text-gray-600'}`}>프리미엄 혜택</a>
                <a href="#platform" onClick={() => {setActiveTab('platform'); setIsMenuOpen(false);}} className={`font-medium ${activeTab === 'platform' ? 'text-blue-600' : 'text-gray-600'}`}>통합 복지몰</a>
                <a href="#cases" onClick={() => {setActiveTab('cases'); setIsMenuOpen(false);}} className={`font-medium ${activeTab === 'cases' ? 'text-blue-600' : 'text-gray-600'}`}>고객 사례</a>
                <a href="#contacts" onClick={() => {setActiveTab('contacts'); setIsMenuOpen(false);}} className={`font-medium ${activeTab === 'contacts' ? 'text-blue-600' : 'text-gray-600'}`}>도입 문의</a>
              </div>
            </div>
          )}
        </div>
      </header>

      {/* Hero 섹션: 서비스 핵심 메시지와 CTA */}
      <section className="pt-32 pb-16 bg-gradient-to-r from-blue-50 to-indigo-50">
        <div className="container mx-auto px-4 flex flex-col md:flex-row items-center">
          {/* 왼쪽: 메시지/버튼 */}
          <div className="md:w-1/2 mb-10 md:mb-0">
            <h1 className="text-4xl md:text-5xl font-bold text-gray-900 mb-4">
              <span className="text-blue-600">LG 라이프케어</span>로<br />임직원 복지의 새로운 기준을 만나다
            </h1>
            <p className="text-lg text-gray-600 mb-8">
              국내 유일의 통합 복지몰, AI 기반 맞춤형 혜택, 자동화된 복지 서비스까지<br />한 번에 경험하세요.
            </p>
            <div className="flex flex-col sm:flex-row space-y-4 sm:space-y-0 sm:space-x-4">
              <button className="bg-blue-600 text-white px-6 py-3 rounded-md font-medium hover:bg-blue-700 transition-colors flex items-center justify-center">
                서비스 소개서 다운로드
                <ArrowRight className="ml-2 h-4 w-4" />
              </button>
              <button className="border border-blue-600 text-blue-600 px-6 py-3 rounded-md font-medium hover:bg-blue-50 transition-colors">
                데모 체험하기
              </button>
            </div>
          </div>
          {/* 오른쪽: 이미지/대시보드 예시 */}
          <div className="md:w-1/2">
            <div className="relative">
              <div className="bg-white rounded-xl shadow-lg overflow-hidden">
                <img src="/api/placeholder/600/400" alt="LG 라이프케어 플랫폼 대시보드" className="w-full" />
              </div>
              <div className="absolute -bottom-4 -left-4 bg-blue-600 text-white px-4 py-2 rounded-lg text-sm font-medium">
                국내 유일 통합 복지몰
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* 서비스 개요(overview) 섹션 */}
      <section id="overview" className="py-12 md:py-16">
        <div className="container mx-auto px-4">
          <div className="text-center mb-8 md:mb-12">
            <h2 className="text-2xl md:text-3xl font-bold text-gray-900 mb-3 md:mb-4">
              <span className="text-blue-600">라이프케어를 선택하는 이유</span>
            </h2>
            <p className="text-base md:text-lg text-gray-600 max-w-3xl mx-auto">
              라이프케어는 LG가 운영하는 국내 유일의 통합 복지몰로 유수의 대형 복지몰 및 폐쇄형 서비스를 통합 제공하고 기업문화와 임직원 DATA의 AI 분석을 통해 생애주기별 맞춤형 복지서비스를 최적의 혜택으로 제공합니다.
            </p>
          </div>
          {/* ... (여기에 overview 상세 내용 추가) ... */}
        </div>
      </section>

      {/* 프리미엄 혜택(benefits) 섹션 */}
      <section id="benefits" className="py-12 md:py-16 bg-blue-50">
        <div className="container mx-auto px-4">
          <div className="text-center mb-8 md:mb-12">
            <h2 className="text-2xl md:text-3xl font-bold text-gray-900 mb-3 md:mb-4">
              <span className="text-blue-600">프리미엄 혜택</span>
            </h2>
            <p className="text-base md:text-lg text-gray-600 max-w-3xl mx-auto">
              LG 계열사 상품 및 서비스를 LG임직원 복지혜택과 동일하게 제공합니다. 국내 유일 통합 복지몰로 최다 상품 및 서비스를 보유하여 임직원 만족도와 기업 로열티를 증대시킵니다.
            </p>
          </div>
          {/* ... (여기에 benefits 상세 내용 추가) ... */}
        </div>
      </section>

      {/* 통합 복지몰(platform) 섹션 */}
      <section id="platform" className="py-12 md:py-16 bg-gray-50">
        <div className="container mx-auto px-4">
          <div className="text-center mb-8 md:mb-12">
            <h2 className="text-2xl md:text-3xl font-bold text-gray-900 mb-3 md:mb-4">
              <span className="text-blue-600">국내 유일의 통합복지몰</span>
            </h2>
            <p className="text-base text-gray-600 max-w-3xl mx-auto">
              LG 계열사 프리미엄 혜택 + 대형 복지몰 + B2C 커머스 종합몰을 모두 통합한 국내 유일의 복지몰입니다. 상품 1억개, 최저가 상품 20만개 및 개인화 상품 추천 서비스를 제공합니다.
            </p>
          </div>
          {/* ... (여기에 platform 상세 내용 추가) ... */}
        </div>
      </section>

      {/* 고객 사례(cases) 섹션 */}
      <section id="cases" className="py-12 md:py-16">
        <div className="container mx-auto px-4">
          <div className="text-center mb-8 md:mb-12">
            <h2 className="text-2xl md:text-3xl font-bold text-gray-900 mb-3 md:mb-4">
              <span className="text-blue-600">고객 성공 사례</span>
            </h2>
            <p className="text-base text-gray-600 max-w-3xl mx-auto">
              다양한 산업 분야의 기업들이 LG 라이프케어와 함께 임직원 경험을 혁신하고 있습니다.
            </p>
          </div>
          {/* ... (여기에 cases 상세 내용 추가) ... */}
        </div>
      </section>

      {/* 도입 문의(contacts) 섹션 */}
      <section id="contacts" className="py-12 md:py-16">
        <div className="container mx-auto px-4">
          <div className="text-center mb-8 md:mb-12">
            <h2 className="text-2xl md:text-3xl font-bold text-gray-900 mb-3 md:mb-4">
              <span className="text-blue-600">도입 문의</span>
            </h2>
            <p className="text-base text-gray-600 max-w-3xl mx-auto">
              복지 플랫폼의 한계를 뛰어넘는 AX 기반의 차세대 임직원 경험을 지금 바로 체험해보세요. 전문 컨설턴트가 귀사에 최적화된 솔루션을 제안해 드립니다.
            </p>
          </div>
          {/* ... (여기에 contacts 상세 내용/문의 폼 추가) ... */}
        </div>
      </section>

      {/* 푸터(footer) 섹션 */}
      <footer className="bg-gray-800 text-white py-10 md:py-12">
        <div className="container mx-auto px-4 text-center">
          <div className="text-xl md:text-2xl font-bold mb-3 md:mb-4">LG 라이프케어</div>
          <p className="text-sm md:text-base text-gray-400 max-w-md mx-auto">
            LG CNS의 IT 기술력을 바탕으로 AX 기반 임직원 복지 경험을 제공하는 차세대 복지 플랫폼입니다.
          </p>
          <div className="mt-8 pt-8 border-t border-gray-700">
            <p className="text-xs md:text-sm text-gray-400 mb-4 md:mb-0">
              © 2025 LG CNS. All rights reserved.
            </p>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default LGLifecareServiceSite;
